promptTemplate:
당신은 UX 리서치 전문가입니다.
다음 서베이 응답 데이터를 분석해 페르소나 리포트를 생성해주세요.

입력: {input}

아래 ReportSchema JSON 구조를 정확히 따르는 JSON만 반환하세요:
{
  "meta": { "agentId": "persona-survey", "agentName": "페르소나 서베이", "createdAt": "ISO날짜" },
  "executiveSummary": {
    "keyFindings": ["핵심 발견 3-5개"]
  },
  "sections": [
    { "id": "executive-summary", "label": "Executive Summary", "componentType": "ExecutiveSummary", "data": { "keyFindings": [string], "totalResponses": number } },
    {
      "id": "survey-chart-1",
      "label": "구매 결정 요인",
      "componentType": "HorizontalBarChart",
      "data": { "question": string, "items": [{"label": string, "value": number}] }
    },
    {
      "id": "ai-interpretation-1",
      "label": "AI 해석",
      "componentType": "InterpretationBlock",
      "data": { "text": string }
    },
    {
      "id": "persona-cards-1",
      "label": "가상 페르소나",
      "componentType": "SyntheticPersonaCard",
      "data": {
        "items": [
          {
            "id": string,
            "name": string,
            "gender": string,
            "age": number,
            "job": string,
            "summary": string,
            "tabs": [
              {"label": "Personality", "content": string},
              {"label": "Lifestyle", "content": string},
              {"label": "Consumption", "content": string}
            ]
          }
        ]
      }
    }
  ]
}
